async function seed() {
  // Step 1: Create database + all tables automatically
  await setupDatabase();

  // Step 2: Get pool connected to the now-existing database
  const p = await getPool();
  const conn = await p.getConnection();

  console.log('🌱 Seeding questions into database...\n');

  try {
    await conn.beginTransaction();

    const insert = async (arr, difficulty) => {
      let inserted = 0;
      let skipped  = 0;
      for (const q of arr) {
        const [result] = await conn.query(
          `INSERT IGNORE INTO questions
           (question_key, question, option_a, option_b, option_c, option_d, answer, subject, difficulty)
           VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)`,
          [q.key, q.q, q.a, q.b, q.c, q.d, q.ans, q.sub, difficulty]
        );
        if (result.affectedRows > 0) inserted++;
        else skipped++;
      }
      console.log(`  ✅ ${difficulty.padEnd(6)} : ${inserted} inserted, ${skipped} already existed`);
    };

    await insert(easy,   'easy');
    await insert(medium, 'medium');
    await insert(hard,   'hard');

    await conn.commit();

    console.log('\n🎉 Database setup complete!');
    console.log('   Easy       : 100 questions  →  10th Standard students');
    console.log('   Medium     : 100 questions  →  12th Standard students');
    console.log('   Hard       : 100 questions  →  Graduation students');
    console.log('\n▶  Now run:  npm start   (or: node server.js)');
    console.log('   Frontend:  cd ../frontend && npm install && npm run dev\n');
  } catch (err) {
    await conn.rollback();
    console.error('\n❌ Seeding failed:', err.message);
    console.error(err);
  } finally {
    conn.release();
    if (pool) await pool.end();
    process.exit(0);
  }
}

seed();
